function calculate({ assetSeniority, leverageRatio, repaymentStructure, covenantProtection, marketEnvironment, sponsorQuality, floatingRateExposure, investmentTerm }) {

  let totalScore = 0;
  let suggestions = [];

  // 1. Asset Class Seniority (Max 20 points)
  let seniorityScore = 0;
  switch (assetSeniority) {
    case 'seniorSecured': seniorityScore = 5; break;
    case 'unitranche': seniorityScore = 10; break;
    case 'juniorMezzanine': seniorityScore = 15; break;
    case 'preferredEquity': seniorityScore = 20; break;
  }
  totalScore += seniorityScore;
  if (seniorityScore >= 15) {
    suggestions.push("Consider prioritizing investments with higher seniority (e.g., Senior Secured Debt) for better recovery prospects in default scenarios.");
  }

  // 2. Borrower Leverage (Net Debt/EBITDA) (Max 20 points)
  let leverageScore = 0;
  if (leverageRatio < 3.0) { leverageScore = 2; }
  else if (leverageRatio >= 3.0 && leverageRatio < 4.5) { leverageScore = 7; }
  else if (leverageRatio >= 4.5 && leverageRatio < 6.0) { leverageScore = 14; }
  else { leverageScore = 20; }
  totalScore += leverageScore;
  if (leverageScore >= 14) {
    suggestions.push("High leverage increases default risk. Seek investments with lower Net Debt/EBITDA ratios or strong cash flow generation.");
  }

  // 3. Repayment Structure (Max 15 points)
  let repaymentScore = 0;
  switch (repaymentStructure) {
    case 'amortizing': repaymentScore = 3; break;
    case 'bullet': repaymentScore = 8; break;
    case 'pik': repaymentScore = 15; break;
  }
  totalScore += repaymentScore;
  if (repaymentScore >= 8) {
    suggestions.push("PIK or Bullet structures carry higher refinancing risk. Amortizing debt offers more predictable cash flow and de-risks over time.");
  }

  // 4. Covenant Protection (Max 15 points)
  let covenantScore = 0;
  switch (covenantProtection) {
    case 'strongMaintenance': covenantScore = 3; break;
    case 'incurrenceOnly': covenantScore = 8; break;
    case 'covenantLite': covenantScore = 15; break;
  }
  totalScore += covenantScore;
  if (covenantScore >= 8) {
    suggestions.push("Covenant-lite deals offer less protection to lenders. Strong maintenance covenants provide early warning signs and greater control.");
  }

  // 5. Underlying Market Environment (Max 10 points)
  let marketScore = 0;
  switch (marketEnvironment) {
    case 'strongGrowth': marketScore = 1; break;
    case 'stable': marketScore = 3; break;
    case 'moderateSlowdown': marketScore = 7; break;
    case 'recessionaryVolatile': marketScore = 10; break;
  }
  totalScore += marketScore;
  if (marketScore >= 7) {
    suggestions.push("In uncertain or recessionary markets, default rates tend to rise. Exercise caution and demand higher risk premiums or stronger credit profiles.");
  }

  // 6. Sponsor/Borrower Quality (Max 10 points)
  let sponsorScore = 0;
  switch (sponsorQuality) {
    case 'investmentGrade': sponsorScore = 1; break;
    case 'midMarketPE': sponsorScore = 5; break;
    case 'smallBusiness': sponsorScore = 10; break;
  }
  totalScore += sponsorScore;
  if (sponsorScore >= 5) {
    suggestions.push("High-quality sponsors or large corporates generally imply better governance, access to capital, and operational expertise. Small businesses carry higher inherent risk.");
  }

  // 7. Interest Rate Exposure (Floating Rate % of Debt) (Max 5 points)
  let interestRateScore = 0;
  if (floatingRateExposure < 25) { interestRateScore = 0; }
  else if (floatingRateExposure >= 25 && floatingRateExposure < 50) { interestRateScore = 2; }
  else if (floatingRateExposure >= 50 && floatingRateExposure < 75) { interestRateScore = 3; }
  else { interestRateScore = 5; }
  totalScore += interestRateScore;
  if (interestRateScore >= 3) {
    suggestions.push("High floating rate exposure can significantly increase interest costs for borrowers in a rising rate environment, impacting their ability to service debt.");
  }

  // 8. Investment Term (Years) (Max 5 points)
  let termScore = 0;
  if (investmentTerm < 3) { termScore = 1; }
  else if (investmentTerm >= 3 && investmentTerm < 5) { termScore = 2; }
  else if (investmentTerm >= 5 && investmentTerm < 7) { termScore = 3; }
  else { termScore = 5; }
  totalScore += termScore;
  if (termScore >= 3) {
    suggestions.push("Longer investment terms often imply greater illiquidity risk and longer exposure to unforeseen market changes. Understand the exit strategy.");
  }

  // Determine Risk Category
  let riskCategory;
  if (totalScore <= 25) { riskCategory = 'Low Risk'; }
  else if (totalScore <= 50) { riskCategory = 'Moderate Risk'; }
  else if (totalScore <= 75) { riskCategory = 'Elevated Risk'; }
  else { riskCategory = 'High Risk'; }

  // Format suggestions
  let finalSuggestions = suggestions.length > 0 ? suggestions.join(' ') : 'No specific high-risk factors identified based on inputs. Always conduct thorough due diligence.';

  return {
    riskScore: totalScore,
    riskCategory: riskCategory,
    mitigationSuggestions: finalSuggestions
  };
}
